[Swift code]:
func calculateESI(socioEcoFactors: [Double], envIndicators: [Double]) -> Double {
  let totalSocioEco = socioEcoFactors.reduce(0, +)
  let totalEnvIndicators = envIndicators.reduce(0, +)
  let avgSocioEco = totalSocioEco / Double(socioEcoFactors.count)
  let avgEnvIndicators = totalEnvIndicators / Double(envIndicators.count)
  let esi = (avgSocioEco + avgEnvIndicators) / 2.0
  return esi
}
