```javascript
function reverseSentences(input) {
  const reverse = (str) => {
    const reversed = str.split('').reverse().join('');
    return reversed;
  };

  const removePunctuation = (str) => {
    return str.replace(/[^\w\s]/gi, '');
  };

  const countWords = (str) => {
    return str.split(/\s+/).length;
  };

  const sentences = input.split(/\.|\?|!|\n/);
  const reversedSentences = sentences.map((sentence) => {
    const words = sentence.split(/\s+/);
    return words.map(removePunctuation).map(reverse).join(' ');
  });

  const table = [['Original Sentence', 'Reversed Sentence', 'Number of Words']];
  for (let i = 0; i < sentences.length; i++) {
    table.push([sentences[i], reversedSentences[i], countWords(sentences[i])]);
  }

  console.log('Reversed sentences:');
  console.log(reversedSentences.join('\n'));
  console.log('\nFormatted table:');
  console.log(table);
}

// Example usage
