Imagine you are building a virtual reality game where players have to collect different types of spells to defeat monsters and progress to higher levels. Each spell has a unique power that can be used to defeat a particular type of monster. However, some spells have synergistic effects that make them more powerful when used in combination with other spells.
For example, the "Fireball" spell is powerful on its own but its power is doubled if used in combination with the "Ice Beam" spell. Similarly, the "Lightning Strike" spell is more powerful when used after the "Water Blast" spell. 
Write a function in JavaScript that takes in an array of spells and their corresponding powers (represented as integers) and returns the total power of each spell, taking into account any synergistic effects. Assume that the synergy multiplier is equal to the square root of the number of other spells that can be used in combination with that particular spell.
```javascript
function calculateTotalSpellPower(spells) {
  let spellPowers = {};
  let spellCounts = {};

  for (let i = 0; i < spells.length; i++) {
    let spell = spells[i][0];
    let power = spells[i][1];

    if (spellPowers[spell]) {
      spellPowers[spell] += power * Math.sqrt(spellCounts[spell] + 1);
      spellCounts[spell]++;
    } else {
      spellPowers[spell] = power * Math.sqrt(1);
      spellCounts[spell] = 1;
    }
  }

  return spellPowers;
}
// Example usage:
let spells = [
  ['Fireball', 10],
  ['Ice Beam', 5],
  ['Fireball', 15],
  ['Water Blast', 20],
  ['Fireball', 20],
  ['Lightning Strike', 25],
  ['Ice Beam', 10]
];
console.log(calculateTotalSpellPower(spells));
